SELECT s.id, s.path, s.name, s.city, COALESCE(i.available_today,0) AS available_today FROM stores s LEFT JOIN inventory i ON i.store_id=s.id AND i.sku IN (
  SELECT sku FROM products WHERE brand='Sika' AND model LIKE '%28T-UV8%' AND json_extract(properties,'$.sealant_type')='hybrid sealant' AND json_extract(properties,'$.color_family')='Gray' AND json_extract(properties,'$.volume')='300 ml'
) WHERE s.city='Vienna' ORDER BY s.id;

